import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager extends ChangeNotifier {
  String? _accessToken;
  String? _refreshToken;
  Map<String, dynamic>? _userData;
  bool _isAuthenticated = false;

  String? get accessToken => _accessToken;
  String? get refreshToken => _refreshToken;
  Map<String, dynamic>? get userData => _userData;
  bool get isAuthenticated => _isAuthenticated;

  AuthManager() {
    _loadAuthData();
  }

  Future<void> _loadAuthData() async {
    final prefs = await SharedPreferences.getInstance();
    _accessToken = prefs.getString('access_token');
    _refreshToken = prefs.getString('refresh_token');
    final userDataString = prefs.getString('user_data');
    if (userDataString != null) {
      _userData = Map<String, dynamic>.from(jsonDecode(userDataString));
    }
    _isAuthenticated = _accessToken != null && _refreshToken != null;
    notifyListeners();
  }

  Future<void> login({
    required String accessToken,
    required String refreshToken,
    required Map<String, dynamic> userData,
  }) async {
    _accessToken = accessToken;
    _refreshToken = refreshToken;
    _userData = userData;
    _isAuthenticated = true;

    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('access_token', accessToken);
    await prefs.setString('refresh_token', refreshToken);
    await prefs.setString('user_data', jsonEncode(userData));

    notifyListeners();
  }

  Future<void> logout() async {
    _accessToken = null;
    _refreshToken = null;
    _userData = null;
    _isAuthenticated = false;

    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('access_token');
    await prefs.remove('refresh_token');
    await prefs.remove('user_data');

    notifyListeners();
  }

  Future<void> refreshTokens() async {
    // Implement token refresh logic here
    // This would typically involve calling your API to get new tokens
    // and then update the shared preferences
  }
}

class AuthProvider extends InheritedWidget {
