  const AuthProvider({
    Key? key,
    required this.authManager,
    required Widget child,
  }) : super(key: key, child: child);

  static AuthManager of(BuildContext context) {
    final AuthProvider? provider = context.dependOnInheritedWidgetOfExactType<AuthProvider>();
    return provider!.authManager;
  }

  @override
  bool updateShouldNotify(covariant AuthProvider oldWidget) {
    return true;
  }
}

